import { Input as InputPrimitive } from "@base-ui/react/input";
import { cn } from "@/lib/utils";

function Input({ className, type, ...props }: React.ComponentProps<"input">) {
  return (
    <InputPrimitive
      type={type}
      data-slot="input"
      className={cn(
        "h-10 w-full min-w-0 rounded-xl border-2 border-input bg-transparent px-4 py-2 text-sm shadow-sm transition-all duration-200",
        "placeholder:text-muted-foreground/60",
        "focus-visible:border-primary/50 focus-visible:shadow-md focus-visible:shadow-primary/10 focus-visible:outline-none",
        "disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50",
        "aria-invalid:border-destructive aria-invalid:ring-2 aria-invalid:ring-destructive/20",
        className
      )}
      {...props}
    />
  );
}

export { Input };

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex h-6 w-fit shrink-0 items-center justify-center gap-1 overflow-hidden rounded-full border border-transparent px-2.5 py-0.5 text-xs font-semibold whitespace-nowrap transition-all focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 aria-invalid:border-destructive aria-invalid:ring-destructive/20 [&>svg]:pointer-events-none [&>svg]:size-3",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground shadow-sm",
        secondary: "bg-secondary text-secondary-foreground",
        destructive: "bg-destructive text-destructive-foreground shadow-sm",
        success: "bg-success text-success-foreground shadow-sm",
        warning: "bg-warning text-warning-foreground shadow-sm",
        outline: "border-border text-foreground",
        ghost: "hover:bg-muted hover:text-muted-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
);

function Badge({
  className,
  variant = "default",
  render,
  ...props
}: useRender.ComponentProps<"span"> & VariantProps<typeof badgeVariants>) {
  return useRender({
    defaultTagName: "span",
    props: mergeProps<"span">(
      {
        className: cn(badgeVariants({ variant }), className),
      },
      props
    ),
    render,
    state: {
      slot: "badge",
      variant,
    },
  });
}

export { Badge, badgeVariants };

import { cn } from "@/lib/utils";

interface SkeletonProps {
  className?: string;
  style?: React.CSSProperties;
}

export function Skeleton({ className, style }: SkeletonProps) {
  return <div className={cn("skeleton rounded-md bg-muted", className)} style={style} />;
}

export function SkeletonLine({ width = "100%", className }: { width?: string; className?: string }) {
  return <Skeleton className={cn("h-4 rounded", className)} style={{ width }} />;
}

export function SkeletonText({ lines = 3, className }: { lines?: number; className?: string }) {
  return (
    <div className={cn("space-y-2", className)}>
      {Array.from({ length: lines }).map((_, i) => (
        <SkeletonLine key={i} width={i === lines - 1 ? "60%" : "100%"} />
      ))}
    </div>
  );
}

export function SkeletonCard({ className }: { className?: string }) {
  return (
    <div className={cn("rounded-2xl border p-4", className)}>
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 space-y-2">
          <SkeletonLine width="40%" />
          <SkeletonLine width="70%" />
          <SkeletonLine width="50%" />
        </div>
        <div className="flex shrink-0 flex-col items-end gap-2">
          <Skeleton className="h-5 w-20 rounded-full" />
          <Skeleton className="h-4 w-10" />
        </div>
      </div>
    </div>
  );
}

export function SkeletonTable({ rows = 5, cols = 6, className }: { rows?: number; cols?: number; className?: string }) {
  return (
    <div className={cn("rounded-xl border", className)}>
      <div className="flex items-center gap-4 border-b bg-muted/30 px-4 py-2.5">
        {Array.from({ length: cols }).map((_, i) => <SkeletonLine key={i} width="35%" className="h-3" />)}
      </div>
      {Array.from({ length: rows }).map((_, i) => (
        <div key={i} className={cn("flex items-center gap-4 px-4 py-3", i < rows - 1 && "border-b")}>
          {Array.from({ length: cols }).map((_, j) => (
            <SkeletonLine key={j} width={j === 0 ? "25%" : `${50 + Math.floor(Math.random() * 40)}%`} className="h-3" />
          ))}
        </div>
      ))}
    </div>
  );
}

import { Badge } from "@/components/ui/badge";
import { getStatusConfig } from "@/features/records/status";
import type { RecordStatus } from "@/features/records/types";
import { cn } from "@/lib/utils";

const toneClasses = {
  info: "border-blue-300/60 bg-blue-50 text-blue-700 dark:border-blue-700/60 dark:bg-blue-950/60 dark:text-blue-200",
  warning:
    "border-amber-300/60 bg-amber-50 text-amber-800 dark:border-amber-700/60 dark:bg-amber-950/60 dark:text-amber-200",
  danger:
    "border-red-300/60 bg-red-50 text-red-700 dark:border-red-700/60 dark:bg-red-950/60 dark:text-red-200",
  success:
    "border-emerald-300/60 bg-emerald-50 text-emerald-700 dark:border-emerald-700/60 dark:bg-emerald-950/60 dark:text-emerald-200",
  neutral:
    "border-slate-300/60 bg-slate-50 text-slate-700 dark:border-slate-600/60 dark:bg-slate-800/60 dark:text-slate-200",
};

const dotClasses = {
  info: "bg-blue-500 shadow-[0_0_6px_rgb(59_130_246/0.5)]",
  warning: "bg-amber-500 shadow-[0_0_6px_rgb(245_158_11/0.5)]",
  danger: "bg-red-500 shadow-[0_0_6px_rgb(239_68_68/0.5)]",
  success: "bg-emerald-500 shadow-[0_0_6px_rgb(16_185_129/0.5)]",
  neutral: "bg-slate-400",
};

interface StatusBadgeProps {
  status: RecordStatus;
  className?: string;
  showIcon?: boolean;
  /** Si true, muestra un punto coloreado en lugar del ícono. */
  showDot?: boolean;
}

export function StatusBadge({
  status,
  className,
  showIcon = true,
  showDot = false,
}: StatusBadgeProps) {
  const config = getStatusConfig(status);
  const Icon = config.icon;

  return (
    <Badge
      variant="outline"
      className={cn(
        "gap-1.5 rounded-full border px-2.5 py-0.5 font-medium transition-colors",
        toneClasses[config.tone],
        className
      )}
    >
      {showDot && (
        <span
          className={cn(
            "size-1.5 rounded-full animate-pulse-soft",
            dotClasses[config.tone]
          )}
        />
      )}
      {showIcon && !showDot && <Icon className="size-3" />}
      {config.label}
    </Badge>
  );
}

import { cn } from "@/lib/utils";

interface PageHeaderProps {
  title: string;
  description?: string;
  action?: React.ReactNode;
  className?: string;
}

export function PageHeader({
  title,
  description,
  action,
  className,
}: PageHeaderProps) {
  return (
    <div
      className={cn(
        "flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between",
        className
      )}
    >
      <div>
        <h1 className="text-2xl font-bold tracking-tight md:text-3xl">
          {title}
        </h1>
        {description && (
          <p className="mt-1.5 max-w-2xl text-sm leading-relaxed text-muted-foreground">
            {description}
          </p>
        )}
      </div>
      {action && <div className="animate-slide-in-right">{action}</div>}
    </div>
  );
}

import Link from "next/link";
import { Images, ChevronRight } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { StatusBadge } from "./StatusBadge";
import type { Record } from "@/features/records/types";
import { formatDate } from "@/lib/format";
import { formatExtractedDateChilean } from "@/lib/date-utils";
import { cn } from "@/lib/utils";

interface RecordSummaryCardProps {
  record: Record;
  href?: string;
  className?: string;
}

export function RecordSummaryCard({
  record,
  href,
  className,
}: RecordSummaryCardProps) {
  const recorrido = record.extraction?.n_recorrido?.valor;
  const fechaRaw = record.extraction?.fecha?.valor;
  const fecha = fechaRaw ? formatExtractedDateChilean(fechaRaw) : undefined;

  const content = (
    <Card
      className={cn(
        "group tap-active transition-all duration-200",
        href && "hover-lift cursor-pointer",
        className
      )}
    >
      <CardContent className="flex items-start justify-between gap-3 p-4">
        <div className="min-w-0 flex-1 space-y-1.5">
          <p className="text-xs text-muted-foreground">
            {formatDate(record.createdAt)}
          </p>
          {recorrido && (
            <p className="truncate font-semibold">
              Recorrido {recorrido}
              {fecha && (
                <span className="ml-1 font-normal text-muted-foreground">
                  · {fecha}
                </span>
              )}
            </p>
          )}
          {record.errorComment && (
            <p className="line-clamp-2 text-xs text-destructive">
              {record.errorComment}
            </p>
          )}
          {href && (
            <div className="flex items-center gap-1 text-xs font-medium text-primary opacity-0 transition-opacity group-hover:opacity-100">
              Revisar <ChevronRight className="size-3" />
            </div>
          )}
        </div>
        <div className="flex shrink-0 flex-col items-end gap-2.5">
          <StatusBadge status={record.status} />
          <span className="inline-flex items-center gap-1 rounded-full bg-muted px-2 py-0.5 text-xs text-muted-foreground">
            <Images className="size-3" />
            {record.images.length}
          </span>
        </div>
      </CardContent>
    </Card>
  );

  if (href) {
    return <Link href={href} className="block">{content}</Link>;
  }

  return content;
}

import type { LucideIcon } from "lucide-react";
import { cn } from "@/lib/utils";

interface EmptyStateProps {
  icon: LucideIcon;
  title: string;
  description?: string;
  action?: React.ReactNode;
  className?: string;
}

export function EmptyState({
  icon: Icon,
  title,
  description,
  action,
  className,
}: EmptyStateProps) {
  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-4 rounded-2xl border-2 border-dashed px-8 py-12 text-center transition-colors hover:border-muted-foreground/20",
        className
      )}
    >
      <div className="flex size-16 items-center justify-center rounded-2xl bg-muted/80 shadow-inner">
        <Icon className="size-7 text-muted-foreground/70" />
      </div>
      <div className="space-y-1.5">
        <p className="text-base font-semibold">{title}</p>
        {description && (
          <p className="max-w-sm text-sm leading-relaxed text-muted-foreground">
            {description}
          </p>
        )}
      </div>
      {action && (
        <div className="pt-2 animate-fade-in-up">{action}</div>
      )}
    </div>
  );
}

import Link from "next/link";
import { Camera } from "lucide-react";
import { buttonVariants } from "@/components/ui/button";
import { COPY } from "@/lib/constants";
import { cn } from "@/lib/utils";

export function CaptureFab() {
  return (
    <div className="fixed inset-x-0 bottom-0 z-40 border-t bg-background/80 p-4 pb-[max(1rem,env(safe-area-inset-bottom))] backdrop-blur-xl supports-[backdrop-filter]:bg-background/60">
      <Link
        href="/driver/capture"
        className={cn(
          buttonVariants({ size: "lg" }),
          "h-14 w-full gap-2.5 rounded-2xl text-base font-semibold shadow-lg shadow-primary/25 transition-all hover:shadow-xl hover:shadow-primary/30 active:scale-[0.98]"
        )}
      >
