      href={`/admin/records/${record.id}/reporte`}
      target="_blank"
      rel="noopener noreferrer"
      className={cn(buttonVariants({ variant, size }), "gap-2")}
    >
      <FileText className="size-4" />
      Reporte ejecutivo
    </Link>
  );
}

